class Solution:
    def minRemoval(self, nums, k):
        nums = sorted(nums)
        n = len(nums)
        best = 1
        for i in range(n):
            for j in range(i, n):
                if nums[j] <= nums[i] * k:
                    best = max(best, j - i + 1)
                else:
                    break
        return n - best

