class Solution:
    def minRemoval(self, nums, k):
        nums.sort()
        n = len(nums)
        best = 0
        i = 0
        for j in range(n):
            while nums[j] > nums[i] * k:
                i += 1
            best = max(best, j - i + 1)
        return n - best

