var minRemoval = function(nums, k) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    let best = 0, i = 0;
    for (let j = 0; j < n; j++) {
        while (nums[j] > nums[i] * k) i++;
        best = Math.max(best, j - i + 1);
    }
    return n - best;
};
